{
  "name": "TutorSync Schedule Pro",
  "description": "A privacy-focused, clean class scheduling application for private tutors to manage multiple students with master and individual monthly views."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Student {
  id: string;
  name: string;
  color: string;
}

export interface ClassSession {
  id: string;
  studentId: string;
  date: string; // ISO format: YYYY-MM-DD
  startTime: string; // HH:mm
  duration: number; // in minutes
  notes?: string;
}

export type ViewType = 'MASTER' | string; // 'MASTER' or Student.id

import React from 'react';

export const COLORS = [
  'bg-blue-100 text-blue-800 border-blue-200',
  'bg-emerald-100 text-emerald-800 border-emerald-200',
  'bg-amber-100 text-amber-800 border-amber-200',
  'bg-rose-100 text-rose-800 border-rose-200',
  'bg-indigo-100 text-indigo-800 border-indigo-200',
  'bg-purple-100 text-purple-800 border-purple-200',
  'bg-cyan-100 text-cyan-800 border-cyan-200',
  'bg-fuchsia-100 text-fuchsia-800 border-fuchsia-200',
];

export const INITIAL_STUDENTS = [
  { id: '1', name: 'Alice Chen', color: COLORS[0] },
  { id: '2', name: 'Bob Smith', color: COLORS[1] },
  { id: '3', name: 'Charlie Davis', color: COLORS[2] },
];

export const getDaysInMonth = (year: number, month: number) => {
  return new Date(year, month + 1, 0).getDate();
};

export const getFirstDayOfMonth = (year: number, month: number) => {
  return new Date(year, month, 1).getDay();
};

export const formatDate = (date: Date) => {
  return date.toISOString().split('T')[0];
};

export const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December'
];

export const formatTime = (time: string) => {
  const [hours, minutes] = time.split(':');
  const h = parseInt(hours, 10);
  const ampm = h >= 12 ? 'PM' : 'AM';
  const hh = h % 12 || 12;
  return `${hh}:${minutes} ${ampm}`;
};

import React, { useState, useEffect } from 'react';
import { Student, ClassSession } from '../types';
import { X } from 'lucide-react';

interface ClassModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (session: Partial<ClassSession>) => void;
  onDelete?: (id: string) => void;
  students: Student[];
  initialData?: Partial<ClassSession>;
}

const ClassModal: React.FC<ClassModalProps> = ({
  isOpen,
  onClose,
  onSave,
  onDelete,
  students,
  initialData
}) => {
  const [studentId, setStudentId] = useState('');
  const [date, setDate] = useState('');
  const [startTime, setStartTime] = useState('15:00');
  const [duration, setDuration] = useState(60);
  const [notes, setNotes] = useState('');

  useEffect(() => {
    if (initialData) {
      setStudentId(initialData.studentId || '');
      setDate(initialData.date || '');
      setStartTime(initialData.startTime || '15:00');
      setDuration(initialData.duration || 60);
      setNotes(initialData.notes || '');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      id: initialData?.id,
      studentId,
      date,
      startTime,
      duration,
      notes
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden">
        <div className="flex items-center justify-between px-6 py-4 border-b">
          <h2 className="text-xl font-bold text-gray-800">
            {initialData?.id ? 'Edit Class' : 'Schedule Class'}
          </h2>
          <button onClick={onClose} className="p-1 hover:bg-gray-100 rounded-full">
            <X className="w-6 h-6 text-gray-500" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Student</label>
            <select
              required
              className="w-full border rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 outline-none"
              value={studentId}
              onChange={(e) => setStudentId(e.target.value)}
            >
              <option value="">Select Student</option>
              {students.map(s => (
                <option key={s.id} value={s.id}>{s.name}</option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Date</label>
            <input
              type="date"
              required
              className="w-full border rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 outline-none"
              value={date}
              onChange={(e) => setDate(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Start Time</label>
              <input
                type="time"
                required
                className="w-full border rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 outline-none"
                value={startTime}
                onChange={(e) => setStartTime(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Duration (min)</label>
              <input
                type="number"
                required
                min="15"
                step="15"
                className="w-full border rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 outline-none"
                value={duration}
                onChange={(e) => setDuration(parseInt(e.target.value))}
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Notes (Optional)</label>
            <textarea
              className="w-full border rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 outline-none"
              rows={2}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="Topic or materials needed..."
            />
          </div>

          <div className="pt-4 flex flex-col gap-2">
            <button
              type="submit"
              className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-semibold py-3 rounded-lg transition-colors"
            >
              Save Schedule
            </button>
            {initialData?.id && onDelete && (
              <button
                type="button"
                onClick={() => {
                  onDelete(initialData.id!);
                  onClose();
                }}
                className="w-full text-rose-600 hover:bg-rose-50 font-medium py-2 rounded-lg transition-colors"
              >
                Delete Class
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default ClassModal;

import React, { useState } from 'react';
import { Student } from '../types';
import { COLORS } from '../constants';
import { X, Plus, Trash2 } from 'lucide-react';

interface StudentModalProps {
  isOpen: boolean;
  onClose: () => void;
  students: Student[];
  onAdd: (name: string, color: string) => void;
  onDelete: (id: string) => void;
}

const StudentModal: React.FC<StudentModalProps> = ({ isOpen, onClose, students, onAdd, onDelete }) => {
  const [newName, setNewName] = useState('');
  const [selectedColor, setSelectedColor] = useState(COLORS[0]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newName.trim()) {
      onAdd(newName.trim(), selectedColor);
      setNewName('');
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden">
        <div className="flex items-center justify-between px-6 py-4 border-b">
          <h2 className="text-xl font-bold text-gray-800">Manage Students</h2>
          <button onClick={onClose} className="p-1 hover:bg-gray-100 rounded-full">
            <X className="w-6 h-6 text-gray-500" />
          </button>
        </div>

        <div className="p-6">
          <form onSubmit={handleSubmit} className="mb-6 space-y-3">
            <div className="flex flex-col gap-3">
              <input
                type="text"
                placeholder="Student Name"
                className="flex-1 border rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 outline-none"
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
              />
              <div className="flex flex-wrap gap-2">
                {COLORS.map((color, idx) => (
                  <button
                    key={idx}
                    type="button"
                    onClick={() => setSelectedColor(color)}
                    className={`w-8 h-8 rounded-full border-2 transition-transform ${color.split(' ')[0]} ${selectedColor === color ? 'border-gray-800 scale-110' : 'border-transparent hover:scale-105'}`}
                  />
                ))}
              </div>
              <button
                type="submit"
                className="bg-indigo-600 hover:bg-indigo-700 text-white font-semibold px-4 py-2.5 rounded-lg flex items-center justify-center gap-2"
              >
                <Plus className="w-5 h-5" /> Add Student
              </button>
            </div>
          </form>

          <div className="space-y-3 max-h-64 overflow-y-auto pr-2">
            {students.length === 0 ? (
              <p className="text-center text-gray-500 py-4 italic">No students added yet.</p>
            ) : (
              students.map(s => (
                <div key={s.id} className="flex items-center justify-between p-3 border rounded-lg bg-gray-50">
                  <div className="flex items-center gap-3">
                    <div className={`w-3 h-3 rounded-full ${s.color.split(' ')[0]}`} />
                    <span className="font-medium text-gray-700">{s.name}</span>
                  </div>
                  <button
                    onClick={() => onDelete(s.id)}
                    className="p-1.5 text-rose-500 hover:bg-rose-50 rounded-lg transition-colors"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StudentModal;

import React, { useState, useEffect, useMemo } from 'react';
import { Student, ClassSession, ViewType } from './types';
import { INITIAL_STUDENTS } from './constants';
import { MONTH_NAMES, getDaysInMonth, getFirstDayOfMonth, formatTime } from './utils/dateUtils';
import ClassModal from './components/ClassModal';
import StudentModal from './components/StudentModal';
import { 
  Users, 
  Calendar as CalendarIcon, 
  Plus, 
  ChevronLeft, 
  ChevronRight, 
  Share2, 
  Settings,
  MoreVertical
} from 'lucide-react';

const App: React.FC = () => {
  // State for data
  const [students, setStudents] = useState<Student[]>(() => {
    const saved = localStorage.getItem('tutor_students');
    return saved ? JSON.parse(saved) : INITIAL_STUDENTS;
  });

  const [classes, setClasses] = useState<ClassSession[]>(() => {
    const saved = localStorage.getItem('tutor_classes');
    return saved ? JSON.parse(saved) : [];
  });

  // UI State
  const [currentView, setCurrentView] = useState<ViewType>('MASTER');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [isClassModalOpen, setIsClassModalOpen] = useState(false);
  const [isStudentModalOpen, setIsStudentModalOpen] = useState(false);
  const [editingClass, setEditingClass] = useState<Partial<ClassSession> | undefined>(undefined);

  // Sync to localStorage
  useEffect(() => {
    localStorage.setItem('tutor_students', JSON.stringify(students));
  }, [students]);

  useEffect(() => {
    localStorage.setItem('tutor_classes', JSON.stringify(classes));
  }, [classes]);

  // Derived Values
  const year = selectedDate.getFullYear();
  const month = selectedDate.getMonth();
  const daysInMonth = getDaysInMonth(year, month);
  const startDay = getFirstDayOfMonth(year, month);
  const currentMonthName = MONTH_NAMES[month];

  const filteredClasses = useMemo(() => {
    return classes.filter(c => {
      const classDate = new Date(c.date);
      const isCorrectMonth = classDate.getFullYear() === year && classDate.getMonth() === month;
      const isCorrectView = currentView === 'MASTER' || c.studentId === currentView;
      return isCorrectMonth && isCorrectView;
    });
  }, [classes, year, month, currentView]);

  const studentMap = useMemo(() => {
    const map = new Map<string, Student>();
    students.forEach(s => map.set(s.id, s));
    return map;
  }, [students]);

  // Handlers
  const handlePrevMonth = () => setSelectedDate(new Date(year, month - 1, 1));
  const handleNextMonth = () => setSelectedDate(new Date(year, month + 1, 1));

  const addOrUpdateClass = (data: Partial<ClassSession>) => {
    if (data.id) {
      setClasses(prev => prev.map(c => c.id === data.id ? { ...c, ...data } as ClassSession : c));
    } else {
      const newClass: ClassSession = {
        ...data as Omit<ClassSession, 'id'>,
        id: Math.random().toString(36).substr(2, 9)
      };
      setClasses(prev => [...prev, newClass]);
    }
    setEditingClass(undefined);
  };

  const deleteClass = (id: string) => {
    setClasses(prev => prev.filter(c => c.id !== id));
  };

  const addStudent = (name: string, color: string) => {
    const newStudent: Student = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      color
    };
    setStudents(prev => [...prev, newStudent]);
  };

  const deleteStudent = (id: string) => {
    setStudents(prev => prev.filter(s => s.id !== id));
    setClasses(prev => prev.filter(c => c.studentId !== id));
    if (currentView === id) setCurrentView('MASTER');
  };

  const handleDayClick = (day: number) => {
    const d = new Date(year, month, day);
    const dateStr = d.toISOString().split('T')[0];
    setEditingClass({ date: dateStr, studentId: currentView === 'MASTER' ? undefined : currentView });
    setIsClassModalOpen(true);
  };

  const handleEditClass = (c: ClassSession) => {
    setEditingClass(c);
    setIsClassModalOpen(true);
  };

  const handlePrint = () => {
    window.print();
  };

  // Render helpers
  const renderCalendar = () => {
    const days = [];
    const dayLabels = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

    // Empty cells for the start of the month
    for (let i = 0; i < startDay; i++) {
      days.push(<div key={`empty-${i}`} className="bg-gray-50 h-32 border border-gray-100"></div>);
    }

    // Actual day cells
    for (let d = 1; d <= daysInMonth; d++) {
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
      const dayClasses = filteredClasses.filter(c => c.date === dateStr);

      days.push(
        <div 
          key={d} 
          onClick={() => handleDayClick(d)}
          className="bg-white h-32 border border-gray-100 p-2 overflow-y-auto hover:bg-indigo-50/30 transition-colors cursor-pointer group"
        >
          <div className="flex justify-between items-start mb-1">
            <span className="text-sm font-semibold text-gray-500">{d}</span>
            <Plus className="w-3 h-3 text-gray-300 opacity-0 group-hover:opacity-100 transition-opacity" />
          </div>
          <div className="space-y-1">
            {dayClasses
              .sort((a, b) => a.startTime.localeCompare(b.startTime))
              .map(c => {
                const s = studentMap.get(c.studentId);
                return (
                  <div 
                    key={c.id}
                    onClick={(e) => {
                      e.stopPropagation();
                      handleEditClass(c);
                    }}
                    className={`text-[10px] leading-tight px-1.5 py-1 rounded border shadow-sm ${s?.color || 'bg-gray-100 text-gray-800'}`}
                  >
                    <div className="font-bold">{formatTime(c.startTime)}</div>
                    {currentView === 'MASTER' && (
                      <div className="truncate">{s?.name || 'Unknown'}</div>
                    )}
                  </div>
                );
              })}
          </div>
        </div>
      );
    }

    return (
      <div className="grid grid-cols-7 border-l border-t border-gray-100 rounded-lg overflow-hidden shadow-sm bg-white">
        {dayLabels.map(label => (
          <div key={label} className="bg-gray-50 py-2 border-r border-b border-gray-100 text-center text-xs font-bold text-gray-400 uppercase tracking-wider">
            {label}
          </div>
        ))}
        {days}
      </div>
    );
  };

  const currentStudent = currentView === 'MASTER' ? null : studentMap.get(currentView);

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar - Hidden on print */}
      <aside className="no-print w-full md:w-64 bg-gray-900 text-gray-300 flex flex-col flex-shrink-0">
        <div className="p-6">
          <div className="flex items-center gap-3 text-white mb-8">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center">
              <CalendarIcon className="w-6 h-6" />
            </div>
            <div>
              <h1 className="text-lg font-bold leading-none">TutorSync</h1>
              <span className="text-xs text-indigo-400 font-medium">Schedule Pro</span>
            </div>
          </div>

          <div className="space-y-1">
            <p className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-2 px-3">Overview</p>
            <button 
              onClick={() => setCurrentView('MASTER')}
              className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors ${currentView === 'MASTER' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'hover:bg-gray-800'}`}
            >
              <Users className="w-4 h-4" />
              <span className="text-sm font-medium">Master Schedule</span>
            </button>
          </div>

          <div className="mt-8 space-y-1 overflow-y-auto max-h-[calc(100vh-320px)]">
            <div className="flex items-center justify-between mb-2 px-3">
              <p className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Students</p>
              <button 
                onClick={() => setIsStudentModalOpen(true)}
                className="p-1 hover:bg-gray-800 rounded text-gray-500 hover:text-indigo-400"
              >
                <Settings className="w-3.5 h-3.5" />
              </button>
            </div>

            {students.map(s => (
              <button 
                key={s.id}
                onClick={() => setCurrentView(s.id)}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors group ${currentView === s.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'hover:bg-gray-800'}`}
              >
                <div className={`w-2 h-2 rounded-full ${s.color.split(' ')[0]} ${currentView === s.id ? 'ring-2 ring-white/30' : ''}`} />
                <span className="text-sm font-medium truncate">{s.name}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="mt-auto p-6 border-t border-gray-800">
          <button 
            onClick={() => {
              setEditingClass({ studentId: currentView === 'MASTER' ? undefined : currentView });
              setIsClassModalOpen(true);
            }}
            className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-semibold py-2.5 rounded-lg flex items-center justify-center gap-2 transition-all active:scale-95 shadow-lg shadow-indigo-600/20"
          >
            <Plus className="w-4 h-4" />
            <span className="text-sm">New Class</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto bg-slate-50">
        {/* Header */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-8 gap-4">
          <div>
            <h2 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
              {currentView === 'MASTER' ? 'Master Overview' : currentStudent?.name}
              <span className="text-lg font-normal text-gray-400 ml-2">/ {currentMonthName}</span>
            </h2>
            <p className="text-gray-500 text-sm mt-1">
              {currentView === 'MASTER' 
                ? 'Showing classes for all students this month.' 
                : `Showing the personal schedule for ${currentStudent?.name}.`
              }
            </p>
          </div>

          <div className="flex items-center gap-3 no-print">
            <div className="flex bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
              <button 
                onClick={handlePrevMonth}
                className="p-2 hover:bg-gray-50 text-gray-600"
              >
                <ChevronLeft className="w-5 h-5" />
              </button>
              <div className="px-4 py-2 text-sm font-semibold text-gray-700 border-x">
                {currentMonthName} {year}
              </div>
              <button 
                onClick={handleNextMonth}
                className="p-2 hover:bg-gray-50 text-gray-600"
              >
                <ChevronRight className="w-5 h-5" />
              </button>
            </div>

            <button 
              onClick={handlePrint}
              className="flex items-center gap-2 px-4 py-2 bg-white rounded-lg shadow-sm border border-gray-200 text-sm font-semibold text-gray-700 hover:bg-gray-50 transition-colors"
            >
              <Share2 className="w-4 h-4" />
              <span className="hidden sm:inline">Export</span>
            </button>
          </div>
        </div>

        {/* Content Area - Optimized for screenshotting */}
        <div className="max-w-6xl mx-auto print:m-0 print:max-w-none">
          {/* Legend for Master View */}
          {currentView === 'MASTER' && (
            <div className="mb-4 flex flex-wrap gap-4 no-print">
              {students.map(s => (
                <div key={s.id} className="flex items-center gap-1.5 bg-white px-3 py-1.5 rounded-full border border-gray-200 text-xs font-medium text-gray-600 shadow-sm">
                  <div className={`w-2.5 h-2.5 rounded-full ${s.color.split(' ')[0]}`} />
                  {s.name}
                </div>
              ))}
            </div>
          )}

          {/* Calendar Grid */}
          <div className="relative">
             {renderCalendar()}
          </div>
        </div>
      </main>

      {/* Modals */}
      <ClassModal 
        isOpen={isClassModalOpen}
        onClose={() => {
          setIsClassModalOpen(false);
          setEditingClass(undefined);
        }}
        onSave={addOrUpdateClass}
        onDelete={deleteClass}
        students={students}
        initialData={editingClass}
      />

      <StudentModal 
        isOpen={isStudentModalOpen}
        onClose={() => setIsStudentModalOpen(false)}
        students={students}
        onAdd={addStudent}
        onDelete={deleteStudent}
      />
    </div>
  );
};

export default App;

export interface Student {
  id: string;
  name: string;
  color: string;
}

export interface ClassSession {
  id: string;
  studentId: string;
  date: string; // ISO format: YYYY-MM-DD
  startTime?: string; // HH:mm (Optional)
  duration?: number; // in minutes (Optional)
  notes?: string;
}

export type ViewType = 'MASTER' | string; // 'MASTER' or Student.id

import React, { useState, useEffect } from 'react';
import { Student, ClassSession } from '../types';
import { X } from 'lucide-react';

interface ClassModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (session: Partial<ClassSession>) => void;
  onDelete?: (id: string) => void;
  students: Student[];
  initialData?: Partial<ClassSession>;
}

const ClassModal: React.FC<ClassModalProps> = ({
  isOpen,
  onClose,
  onSave,
  onDelete,
  students,
  initialData
}) => {
  const [studentId, setStudentId] = useState('');
  const [date, setDate] = useState('');
  const [startTime, setStartTime] = useState('');
  const [duration, setDuration] = useState<number | undefined>(undefined);
  const [notes, setNotes] = useState('');

  useEffect(() => {
    if (initialData) {
      setStudentId(initialData.studentId || '');
      setDate(initialData.date || '');
      setStartTime(initialData.startTime || '');
      setDuration(initialData.duration);
      setNotes(initialData.notes || '');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      id: initialData?.id,
      studentId,
      date,
      startTime: startTime || undefined,
      duration: duration || undefined,
      notes
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden">
        <div className="flex items-center justify-between px-6 py-4 border-b">
          <h2 className="text-xl font-bold text-gray-800">
            {initialData?.id ? 'Edit Class Details' : 'Schedule Class'}
          </h2>
          <button onClick={onClose} className="p-1 hover:bg-gray-100 rounded-full">
            <X className="w-6 h-6 text-gray-500" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Student</label>
            <select
              required
              className="w-full border rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 outline-none"
              value={studentId}
              onChange={(e) => setStudentId(e.target.value)}
            >
              <option value="">Select Student</option>
              {students.map(s => (
                <option key={s.id} value={s.id}>{s.name}</option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Date</label>
            <input
              type="date"
              required
              className="w-full border rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 outline-none"
              value={date}
              onChange={(e) => setDate(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1 text-gray-400">Time (Optional)</label>
              <input
                type="time"
                className="w-full border rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 outline-none"
                value={startTime}
                onChange={(e) => setStartTime(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1 text-gray-400">Duration (Optional)</label>
              <input
                type="number"
                min="0"
                step="15"
                placeholder="60 min"
                className="w-full border rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 outline-none"
                value={duration || ''}
                onChange={(e) => setDuration(e.target.value ? parseInt(e.target.value) : undefined)}
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Notes (Optional)</label>
            <textarea
              className="w-full border rounded-lg p-2.5 focus:ring-2 focus:ring-indigo-500 outline-none"
              rows={2}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="Topic or materials needed..."
            />
          </div>

          <div className="pt-4 flex flex-col gap-2">
            <button
              type="submit"
              className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-semibold py-3 rounded-lg transition-colors"
            >
              Save Details
            </button>
            {initialData?.id && onDelete && (
              <button
                type="button"
                onClick={() => {
                  onDelete(initialData.id!);
                  onClose();
                }}
                className="w-full text-rose-600 hover:bg-rose-50 font-medium py-2 rounded-lg transition-colors"
              >
                Remove from Calendar
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

