  const renderCalendar = () => {
    const days = [];
    const dayLabels = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

    // Empty cells for the start of the month
    for (let i = 0; i < startDay; i++) {
      days.push(<div key={`empty-${i}`} className="bg-gray-50 h-32 border border-gray-100"></div>);
    }

    // Actual day cells
    for (let d = 1; d <= daysInMonth; d++) {
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
      const dayClasses = filteredClasses.filter(c => c.date === dateStr);

      days.push(
        <div 
          key={d} 
          onClick={() => handleDayClick(d)}
          className={`h-32 border border-gray-100 p-2 overflow-y-auto transition-colors cursor-pointer group relative ${currentView !== 'MASTER' ? 'hover:bg-indigo-50/50 bg-white' : 'bg-white hover:bg-gray-50'}`}
        >
          <div className="flex justify-between items-start mb-1">
            <span className="text-sm font-semibold text-gray-400 group-hover:text-indigo-600 transition-colors">{d}</span>
            {currentView !== 'MASTER' && (
              <Plus className="w-3.5 h-3.5 text-indigo-300 opacity-0 group-hover:opacity-100 transition-opacity" />
            )}
          </div>
          <div className="space-y-1">
            {dayClasses
              .sort((a, b) => (a.startTime || '00:00').localeCompare(b.startTime || '00:00'))
              .map(c => {
                const s = studentMap.get(c.studentId);
                return (
                  <div 
                    key={c.id}
                    onClick={(e) => handleClassDetailsClick(e, c)}
                    className={`px-1.5 py-1 rounded border shadow-sm transition-transform active:scale-95 ${s?.color || 'bg-gray-100 text-gray-800'}`}
                  >
                    <div className="flex flex-col gap-0.5">
                      <div className="text-[10px] font-bold truncate">
                        {c.startTime ? formatTime(c.startTime) : s?.name}
                      </div>
                      {currentView === 'MASTER' && c.startTime && (
                        <div className="text-[10px] truncate opacity-80">{s?.name}</div>
                      )}
                    </div>
                  </div>
                );
              })}
          </div>
        </div>
      );
    }

    return (
      <div className="grid grid-cols-7 border-l border-t border-gray-100 rounded-xl overflow-hidden shadow-sm bg-white">
        {dayLabels.map(label => (
          <div key={label} className="bg-gray-50 py-3 border-r border-b border-gray-100 text-center text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em]">
            {label}
          </div>
        ))}
        {days}
      </div>
    );
  };

  const currentStudent = currentView === 'MASTER' ? null : studentMap.get(currentView);

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#f8fafc]">
      {/* Sidebar - Hidden on print */}
      <aside className="no-print w-full md:w-64 bg-white border-r border-gray-200 flex flex-col flex-shrink-0">
        <div className="p-6">
          <div className="flex items-center gap-3 text-indigo-600 mb-10">
            <div className="w-9 h-9 bg-indigo-600 rounded-lg flex items-center justify-center text-white shadow-lg shadow-indigo-200">
              <CalendarIcon className="w-5 h-5" />
            </div>
            <div>
              <h1 className="text-base font-bold text-gray-900 leading-none">TutorSync</h1>
              <span className="text-[10px] text-gray-400 font-semibold tracking-wider uppercase">Planner</span>
            </div>
          </div>

          <div className="space-y-1.5">
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-3 px-3">Main View</p>
            <button 
              onClick={() => setCurrentView('MASTER')}
              className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${currentView === 'MASTER' ? 'bg-indigo-50 text-indigo-700 font-semibold shadow-sm border border-indigo-100' : 'text-gray-500 hover:bg-gray-50'}`}
            >
              <Users className="w-4 h-4" />
              <span className="text-sm">Master Schedule</span>
            </button>
          </div>

          <div className="mt-10 space-y-1.5 overflow-y-auto max-h-[calc(100vh-320px)]">
            <div className="flex items-center justify-between mb-3 px-3">
              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Student Sheets</p>
              <button 
                onClick={() => setIsStudentModalOpen(true)}
                className="p-1.5 hover:bg-gray-50 rounded-lg text-gray-400 hover:text-indigo-600 transition-colors"
                title="Manage Students"
              >
                <Settings className="w-4 h-4" />
              </button>
            </div>

            {students.map(s => (
              <button 
                key={s.id}
                onClick={() => setCurrentView(s.id)}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all group ${currentView === s.id ? 'bg-indigo-50 text-indigo-700 font-semibold shadow-sm border border-indigo-100' : 'text-gray-500 hover:bg-gray-50'}`}
              >
                <div className={`w-2.5 h-2.5 rounded-full border-2 border-white ${s.color.split(' ')[0]} ${currentView === s.id ? 'scale-110 shadow-sm' : ''}`} />
                <span className="text-sm truncate">{s.name}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="mt-auto p-6 bg-gray-50/50 border-t border-gray-100">
          <div className="text-[10px] font-medium text-gray-400 mb-2 px-1 text-center">Tip: Click calendar days to paint schedule</div>
          <button 
            onClick={() => {
              setEditingClass({ studentId: currentView === 'MASTER' ? undefined : currentView });
              setIsClassModalOpen(true);
            }}
            className="w-full bg-white border border-gray-200 hover:border-indigo-300 hover:text-indigo-600 text-gray-600 font-semibold py-2.5 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm active:scale-95"
          >
            <Plus className="w-4 h-4" />
            <span className="text-sm">Advanced New</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-h-0 overflow-hidden">
        {/* Header */}
        <header className="no-print bg-white border-b border-gray-200 px-6 py-4 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
             <div className="bg-indigo-50 p-2 rounded-lg">
                <CalendarIcon className="w-5 h-5 text-indigo-600" />
             </div>
             <div>
                <h2 className="text-lg font-bold text-gray-900 flex items-center gap-2">
                  {currentView === 'MASTER' ? 'Master Overview' : `${currentStudent?.name}'s Schedule`}
                </h2>
                <div className="flex items-center gap-1.5 text-gray-400 text-[11px] font-medium uppercase tracking-wider">
                  <span>{currentMonthName} {year}</span>
                  {currentView !== 'MASTER' && (
                    <>
                      <span className="text-gray-200">|</span>
                      <span className="text-indigo-500">Painter Mode Active</span>
                    </>
                  )}
                </div>
             </div>
          </div>

          <div className="flex items-center gap-3">
            <div className="flex bg-gray-50 rounded-xl p-1 border border-gray-100">
              <button 
                onClick={handlePrevMonth}
                className="p-1.5 hover:bg-white hover:shadow-sm rounded-lg transition-all text-gray-500"
              >
                <ChevronLeft className="w-4 h-4" />
              </button>
              <div className="px-3 py-1.5 text-xs font-bold text-gray-700 min-w-[120px] text-center">
                {currentMonthName}
              </div>
              <button 
                onClick={handleNextMonth}
                className="p-1.5 hover:bg-white hover:shadow-sm rounded-lg transition-all text-gray-500"
              >
                <ChevronRight className="w-4 h-4" />
              </button>
            </div>

            <button 
              onClick={handlePrint}
              className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 rounded-xl text-white text-xs font-bold transition-all shadow-lg shadow-indigo-100 active:scale-95"
            >
              <Share2 className="w-3.5 h-3.5" />
              Export View
            </button>
          </div>
        </header>

        {/* Content Area - Optimized for screenshotting */}
        <div className="flex-1 overflow-y-auto p-6 md:p-10">
          <div className="max-w-5xl mx-auto">
            {/* Legend for Master View */}
            {currentView === 'MASTER' && (
              <div className="mb-6 flex flex-wrap gap-2.5 no-print">
                {students.map(s => (
                  <div key={s.id} className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border border-gray-100 text-[11px] font-semibold text-gray-600 shadow-sm transition-all hover:border-indigo-100">
                    <div className={`w-2 h-2 rounded-full ${s.color.split(' ')[0]}`} />
                    {s.name}
                  </div>
                ))}
                {students.length === 0 && (
                   <p className="text-[11px] text-gray-400 italic bg-gray-50 px-3 py-1.5 rounded-lg">No students added. Use settings icon to add students.</p>
                )}
              </div>
            )}

            {currentView !== 'MASTER' && (
               <div className="mb-6 flex items-center gap-3 px-4 py-3 bg-indigo-50 border border-indigo-100 rounded-xl no-print">
                  <Info className="w-4 h-4 text-indigo-500" />
                  <p className="text-xs text-indigo-700 font-medium">
                    <strong className="font-bold">Painter Mode:</strong> Click any day to toggle <span className="underline decoration-indigo-300 decoration-2 underline-offset-2">{currentStudent?.name}</span> on that date.
                  </p>
               </div>
            )}

            {/* Calendar Grid */}
            <div className="print:m-0">
               {renderCalendar()}
            </div>

            <footer className="mt-8 text-center no-print">
               <p className="text-gray-400 text-[10px] font-medium tracking-wide">© TutorSync Schedule Pro — Privacy Protected Sheet</p>
            </footer>
          </div>
        </div>
      </main>

      {/* Modals */}
      <ClassModal 
        isOpen={isClassModalOpen}
        onClose={() => {
          setIsClassModalOpen(false);
          setEditingClass(undefined);
        }}
        onSave={addOrUpdateClass}
        onDelete={deleteClass}
        students={students}
        initialData={editingClass}
      />

      <StudentModal 
        isOpen={isStudentModalOpen}
        onClose={() => setIsStudentModalOpen(false)}
        students={students}
        onAdd={addStudent}
        onDelete={deleteStudent}
      />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Student } from '../types';
import { COLORS } from '../constants';
import { X, Plus, Trash2, AlertCircle } from 'lucide-react';

interface StudentModalProps {
  isOpen: boolean;
  onClose: () => void;
  students: Student[];
  onAdd: (name: string, color: string) => void;
  onDelete: (id: string) => void;
}

const StudentModal: React.FC<StudentModalProps> = ({ isOpen, onClose, students, onAdd, onDelete }) => {
  const [newName, setNewName] = useState('');
  const [selectedColor, setSelectedColor] = useState(COLORS[0]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newName.trim() && students.length < 20) {
      onAdd(newName.trim(), selectedColor);
      setNewName('');
      // Auto-pick next color for convenience
      const currentIndex = COLORS.indexOf(selectedColor);
      setSelectedColor(COLORS[(currentIndex + 1) % COLORS.length]);
    }
  };

  const isLimitReached = students.length >= 20;

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
          <div>
            <h2 className="text-xl font-bold text-gray-800">Manage Students</h2>
            <p className="text-xs text-gray-400 font-medium">{students.length} / 20 students added</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-xl transition-colors">
            <X className="w-5 h-5 text-gray-500" />
          </button>
        </div>

        <div className="p-6">
          <form onSubmit={handleSubmit} className="mb-8 space-y-4">
            <div className="space-y-3">
              <label className="text-xs font-bold text-gray-400 uppercase tracking-wider ml-1">Add New Student</label>
              <input
                type="text"
                disabled={isLimitReached}
                placeholder={isLimitReached ? "Limit reached (20 students)" : "Student Full Name"}
                className={`w-full border rounded-xl p-3 focus:ring-2 focus:ring-indigo-500 outline-none transition-all ${isLimitReached ? 'bg-gray-50 cursor-not-allowed opacity-60' : 'bg-white'}`}
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
              />

              <div className="grid grid-cols-10 gap-2 p-1">
                {COLORS.map((color, idx) => (
                  <button
                    key={idx}
                    type="button"
                    disabled={isLimitReached}
                    onClick={() => setSelectedColor(color)}
                    className={`w-6 h-6 rounded-full border-2 transition-all ${color.split(' ')[0]} ${selectedColor === color ? 'border-gray-800 scale-125 shadow-sm' : 'border-transparent hover:scale-110 opacity-80 hover:opacity-100'}`}
                    title={`Color option ${idx + 1}`}
                  />
                ))}
              </div>

              <button
                type="submit"
                disabled={isLimitReached || !newName.trim()}
                className={`w-full font-bold px-4 py-3 rounded-xl flex items-center justify-center gap-2 transition-all active:scale-[0.98] ${isLimitReached || !newName.trim() ? 'bg-gray-100 text-gray-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-lg shadow-indigo-100'}`}
              >
                <Plus className="w-5 h-5" /> Add to Roster
              </button>

              {isLimitReached && (
                <div className="flex items-center gap-2 px-3 py-2 bg-amber-50 rounded-lg text-[10px] font-bold text-amber-700 border border-amber-100">
                   <AlertCircle className="w-3.5 h-3.5" />
                   Maximum of 20 students reached.
                </div>
              )}
            </div>
          </form>

          <div className="space-y-2 max-h-60 overflow-y-auto pr-2 custom-scrollbar">
            <label className="text-xs font-bold text-gray-400 uppercase tracking-wider ml-1">Current Roster</label>
            {students.length === 0 ? (
              <div className="text-center py-8 border-2 border-dashed border-gray-100 rounded-2xl">
                <p className="text-sm text-gray-400 font-medium">Your roster is empty.</p>
              </div>
            ) : (
              students.map(s => (
                <div key={s.id} className="flex items-center justify-between p-3 border border-gray-100 rounded-xl bg-gray-50/50 hover:bg-white hover:shadow-sm transition-all group">
                  <div className="flex items-center gap-3">
                    <div className={`w-3 h-3 rounded-full shadow-sm ${s.color.split(' ')[0]}`} />
                    <span className="font-semibold text-gray-700 text-sm">{s.name}</span>
                  </div>
                  <button
                    onClick={() => onDelete(s.id)}
                    className="p-2 text-gray-400 hover:text-rose-500 hover:bg-rose-50 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                    title="Remove Student"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

