import React, { useState, useEffect } from 'react';
import { Student, ClassSession } from '../types';
import { X } from 'lucide-react';

interface ClassModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (session: Partial<ClassSession>) => void;
  onDelete?: (id: string) => void;
  students: Student[];
  initialData?: Partial<ClassSession>;
}

const ClassModal: React.FC<ClassModalProps> = ({
  isOpen,
  onClose,
  onSave,
  onDelete,
  students,
  initialData
}) => {
  const [studentId, setStudentId] = useState('');
  const [date, setDate] = useState('');
  const [startTime, setStartTime] = useState('');
  const [duration, setDuration] = useState<number | undefined>(undefined);
  const [notes, setNotes] = useState('');

  useEffect(() => {
    if (initialData) {
      setStudentId(initialData.studentId || '');
      setDate(initialData.date || '');
      setStartTime(initialData.startTime || '');
      setDuration(initialData.duration);
      setNotes(initialData.notes || '');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      id: initialData?.id,
      studentId,
      date,
      startTime: startTime || undefined,
      duration: duration || undefined,
      notes
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden">
        <div className="flex items-center justify-between px-6 py-4 border-b">
          <h2 className="text-xl font-bold text-gray-800">
            {initialData?.id ? 'Edit Class Details' : 'Schedule Class'}
          </h2>
          <button onClick={onClose} className="p-1 hover:bg-gray-100 rounded-full">
            <X className="w-6 h-6 text-gray-500" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Student</label>
            <select
              required
              className="w-full border rounded-lg p-2.5 text-gray-900 bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              value={studentId}
              onChange={(e) => setStudentId(e.target.value)}
            >
              <option value="">Select Student</option>
              {students.map(s => (
                <option key={s.id} value={s.id}>{s.name}</option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Date</label>
            <input
              type="date"
              required
              className="w-full border rounded-lg p-2.5 text-gray-900 bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              value={date}
              onChange={(e) => setDate(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-600 mb-1">Time (Optional)</label>
              <input
                type="time"
                className="w-full border rounded-lg p-2.5 text-gray-900 bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                value={startTime}
                onChange={(e) => setStartTime(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-600 mb-1">Duration (Optional)</label>
              <input
                type="number"
                min="0"
                step="15"
                placeholder="60 min"
                className="w-full border rounded-lg p-2.5 text-gray-900 bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
                value={duration || ''}
                onChange={(e) => setDuration(e.target.value ? parseInt(e.target.value) : undefined)}
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Notes (Optional)</label>
            <textarea
              className="w-full border rounded-lg p-2.5 text-gray-900 bg-white focus:ring-2 focus:ring-indigo-500 outline-none"
              rows={2}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="Topic or materials needed..."
            />
          </div>

          <div className="pt-4 flex flex-col gap-2">
            <button
              type="submit"
              className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-semibold py-3 rounded-lg transition-colors"
            >
              Save Details
            </button>
            {initialData?.id && onDelete && (
              <button
                type="button"
                onClick={() => {
                  onDelete(initialData.id!);
                  onClose();
                }}
                className="w-full text-rose-600 hover:bg-rose-50 font-medium py-2 rounded-lg transition-colors"
              >
                Remove from Calendar
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default ClassModal;

export interface Student {
  id: string;
  name: string;
  color: string;
}

export interface ClassSession {
  id: string;
  studentId?: string; // Optional for general events
  title?: string;     // For general events like "School Break"
  type: 'SESSION' | 'EVENT';
  date: string;       // ISO format: YYYY-MM-DD
  startTime?: string; // HH:mm (Optional)
  duration?: number;  // in minutes (Optional)
  notes?: string;
}

export type ViewType = 'MASTER' | string; // 'MASTER' or Student.id

import React, { useState, useEffect } from 'react';
import { Student, ClassSession } from '../types';
import { X, GraduationCap, Calendar as CalendarIcon } from 'lucide-react';

interface ClassModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (session: Partial<ClassSession>) => void;
  onDelete?: (id: string) => void;
  students: Student[];
  initialData?: Partial<ClassSession>;
}

const ClassModal: React.FC<ClassModalProps> = ({
  isOpen,
  onClose,
  onSave,
  onDelete,
  students,
  initialData
}) => {
  const [type, setType] = useState<'SESSION' | 'EVENT'>('SESSION');
  const [studentId, setStudentId] = useState('');
  const [title, setTitle] = useState('');
  const [date, setDate] = useState('');
  const [startTime, setStartTime] = useState('');
  const [duration, setDuration] = useState<number | undefined>(undefined);
  const [notes, setNotes] = useState('');

  useEffect(() => {
    if (initialData) {
      setType(initialData.type || (initialData.studentId ? 'SESSION' : 'EVENT'));
      setStudentId(initialData.studentId || '');
      setTitle(initialData.title || '');
      setDate(initialData.date || '');
      setStartTime(initialData.startTime || '');
      setDuration(initialData.duration);
      setNotes(initialData.notes || '');
    } else {
      setType('SESSION');
      setStudentId('');
      setTitle('');
      setDate('');
      setStartTime('');
      setDuration(undefined);
      setNotes('');
    }
  }, [initialData, isOpen]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      id: initialData?.id,
      type,
      studentId: type === 'SESSION' ? studentId : undefined,
      title: type === 'EVENT' ? title : undefined,
      date,
      startTime: startTime || undefined,
      duration: duration || undefined,
      notes
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
          <h2 className="text-xl font-bold text-gray-800">
            {initialData?.id ? 'Edit Entry' : 'Add to Schedule'}
          </h2>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-xl transition-colors">
            <X className="w-5 h-5 text-gray-500" />
          </button>
        </div>

        {/* Type Toggle */}
        <div className="flex p-1 bg-gray-100 mx-6 mt-6 rounded-xl">
          <button
            onClick={() => setType('SESSION')}
            className={`flex-1 flex items-center justify-center gap-2 py-2 text-xs font-bold rounded-lg transition-all ${type === 'SESSION' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            <GraduationCap className="w-4 h-4" />
            Student Class
          </button>
          <button
            onClick={() => setType('EVENT')}
            className={`flex-1 flex items-center justify-center gap-2 py-2 text-xs font-bold rounded-lg transition-all ${type === 'EVENT' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            <CalendarIcon className="w-4 h-4" />
            General Event
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          {type === 'SESSION' ? (
            <div>
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 ml-1">Student</label>
              <select
                required
                className="w-full border border-gray-200 rounded-xl p-3 text-gray-900 bg-gray-50/50 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
                value={studentId}
                onChange={(e) => setStudentId(e.target.value)}
              >
                <option value="">Select a student...</option>
                {students.map(s => (
                  <option key={s.id} value={s.id}>{s.name}</option>
                ))}
              </select>
            </div>
          ) : (
            <div>
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 ml-1">Event Title</label>
              <input
                type="text"
                required
                placeholder="e.g. Math Workshop, School Holiday"
                className="w-full border border-gray-200 rounded-xl p-3 text-gray-900 bg-gray-50/50 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
              />
            </div>
          )}

          <div>
            <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 ml-1">Date</label>
            <input
              type="date"
              required
              className="w-full border border-gray-200 rounded-xl p-3 text-gray-900 bg-gray-50/50 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
              value={date}
              onChange={(e) => setDate(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 ml-1 text-gray-400">Time (Opt)</label>
              <input
                type="time"
                className="w-full border border-gray-200 rounded-xl p-3 text-gray-900 bg-gray-50/50 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
                value={startTime}
                onChange={(e) => setStartTime(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 ml-1 text-gray-400">Min (Opt)</label>
              <input
                type="number"
                min="0"
                step="15"
                placeholder="60"
                className="w-full border border-gray-200 rounded-xl p-3 text-gray-900 bg-gray-50/50 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
                value={duration || ''}
                onChange={(e) => setDuration(e.target.value ? parseInt(e.target.value) : undefined)}
              />
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 ml-1 text-gray-400">Notes</label>
            <textarea
              className="w-full border border-gray-200 rounded-xl p-3 text-gray-900 bg-gray-50/50 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
              rows={2}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="Any additional details..."
            />
          </div>

          <div className="pt-4 flex flex-col gap-2">
            <button
              type="submit"
              className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-indigo-100 active:scale-[0.98]"
            >
              Save to Schedule
            </button>
            {initialData?.id && onDelete && (
              <button
                type="button"
                onClick={() => {
                  onDelete(initialData.id!);
                  onClose();
                }}
                className="w-full text-rose-600 hover:bg-rose-50 font-bold py-2 rounded-xl transition-all"
              >
                Delete Entry
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default ClassModal;

import React, { useState, useEffect, useMemo } from 'react';
import { Student, ClassSession, ViewType } from './types';
import { INITIAL_STUDENTS } from './constants';
import { MONTH_NAMES, getDaysInMonth, getFirstDayOfMonth, formatTime } from './utils/dateUtils';
import ClassModal from './components/ClassModal';
import StudentModal from './components/StudentModal';
import { 
  Users, 
  Calendar as CalendarIcon, 
  Plus, 
  ChevronLeft, 
  ChevronRight, 
  Share2, 
  Settings,
  Info,
  Star
} from 'lucide-react';

const App: React.FC = () => {
  // State for data
  const [students, setStudents] = useState<Student[]>(() => {
    const saved = localStorage.getItem('tutor_students');
    return saved ? JSON.parse(saved) : INITIAL_STUDENTS;
  });

  const [classes, setClasses] = useState<ClassSession[]>(() => {
    const saved = localStorage.getItem('tutor_classes');
    return saved ? JSON.parse(saved) : [];
  });

  // UI State
  const [currentView, setCurrentView] = useState<ViewType>('MASTER');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [isClassModalOpen, setIsClassModalOpen] = useState(false);
  const [isStudentModalOpen, setIsStudentModalOpen] = useState(false);
  const [editingClass, setEditingClass] = useState<Partial<ClassSession> | undefined>(undefined);

  // Sync to localStorage
  useEffect(() => {
    localStorage.setItem('tutor_students', JSON.stringify(students));
  }, [students]);

  useEffect(() => {
    localStorage.setItem('tutor_classes', JSON.stringify(classes));
  }, [classes]);

  // Derived Values
  const year = selectedDate.getFullYear();
  const month = selectedDate.getMonth();
  const daysInMonth = getDaysInMonth(year, month);
  const startDay = getFirstDayOfMonth(year, month);
  const currentMonthName = MONTH_NAMES[month];

  const filteredClasses = useMemo(() => {
    return classes.filter(c => {
      // Handle the date comparison safely without UTC shifts
      const [cYear, cMonth] = c.date.split('-').map(Number);
      const isCorrectMonth = cYear === year && (cMonth - 1) === month;

      if (currentView === 'MASTER') return isCorrectMonth;
      // In individual views, only show SESSIONS for that specific student
      return isCorrectMonth && c.type === 'SESSION' && c.studentId === currentView;
    });
  }, [classes, year, month, currentView]);

  const studentMap = useMemo(() => {
    const map = new Map<string, Student>();
    students.forEach(s => map.set(s.id, s));
    return map;
  }, [students]);

  // Handlers
  const handlePrevMonth = () => setSelectedDate(new Date(year, month - 1, 1));
  const handleNextMonth = () => setSelectedDate(new Date(year, month + 1, 1));

  const addOrUpdateClass = (data: Partial<ClassSession>) => {
    if (data.id) {
      setClasses(prev => prev.map(c => c.id === data.id ? { ...c, ...data } as ClassSession : c));
    } else {
      const newClass: ClassSession = {
        ...data as Omit<ClassSession, 'id'>,
        id: Math.random().toString(36).substr(2, 9)
      };
      setClasses(prev => [...prev, newClass]);
    }
    setEditingClass(undefined);
  };

  const deleteClass = (id: string) => {
    setClasses(prev => prev.filter(c => c.id !== id));
  };

  const addStudent = (name: string, color: string) => {
    const newStudent: Student = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      color
    };
    setStudents(prev => [...prev, newStudent]);
  };

  const deleteStudent = (id: string) => {
    setStudents(prev => prev.filter(s => s.id !== id));
    setClasses(prev => prev.filter(c => c.studentId !== id));
    if (currentView === id) setCurrentView('MASTER');
  };

  const handleDayClick = (day: number) => {
    const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

    if (currentView !== 'MASTER') {
      // QUICK SCHEDULE MODE: Toggle the current student for this day
      const existingClassIdx = classes.findIndex(c => c.date === dateStr && c.studentId === currentView && c.type === 'SESSION');

      if (existingClassIdx > -1) {
        setClasses(prev => prev.filter((_, i) => i !== existingClassIdx));
      } else {
        const newClass: ClassSession = {
          id: Math.random().toString(36).substr(2, 9),
          studentId: currentView,
          type: 'SESSION',
          date: dateStr
        };
        setClasses(prev => [...prev, newClass]);
      }
    } else {
      // Master view: Open modal to let user choose student OR global event
      setEditingClass({ date: dateStr, type: 'SESSION' });
      setIsClassModalOpen(true);
    }
  };

  const handleClassDetailsClick = (e: React.MouseEvent, c: ClassSession) => {
    e.stopPropagation();
    setEditingClass(c);
    setIsClassModalOpen(true);
  };

  const handlePrint = () => {
    window.print();
  };

  // Render helpers
  const renderCalendar = () => {
    const days = [];
    const dayLabels = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

    for (let i = 0; i < startDay; i++) {
      days.push(<div key={`empty-${i}`} className="bg-gray-50 h-32 border border-gray-100"></div>);
    }

    for (let d = 1; d <= daysInMonth; d++) {
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
      const dayClasses = filteredClasses.filter(c => c.date === dateStr);

      days.push(
        <div 
          key={d} 
          onClick={() => handleDayClick(d)}
          className={`h-32 border border-gray-100 p-2 overflow-y-auto transition-colors cursor-pointer group relative ${currentView !== 'MASTER' ? 'hover:bg-indigo-50/50 bg-white' : 'bg-white hover:bg-gray-50'}`}
        >
          <div className="flex justify-between items-start mb-1">
            <span className="text-sm font-semibold text-gray-400 group-hover:text-indigo-600 transition-colors">{d}</span>
            {currentView !== 'MASTER' && (
              <Plus className="w-3.5 h-3.5 text-indigo-300 opacity-0 group-hover:opacity-100 transition-opacity" />
            )}
          </div>
          <div className="space-y-1">
            {dayClasses
              .sort((a, b) => (a.startTime || '00:00').localeCompare(b.startTime || '00:00'))
              .map(c => {
                if (c.type === 'EVENT') {
                  // General Event Styling (Full width, dark grey)
                  return (
                    <div 
                      key={c.id}
                      onClick={(e) => handleClassDetailsClick(e, c)}
                      className="px-1.5 py-1 rounded border shadow-sm transition-transform active:scale-95 bg-gray-800 text-white border-gray-900"
                    >
                      <div className="flex items-center gap-1">
                        <Star className="w-2 h-2 text-amber-400 fill-amber-400" />
                        <div className="text-[10px] font-bold truncate">
                          {c.startTime ? `${formatTime(c.startTime)} ` : ''}{c.title}
                        </div>
                      </div>
                    </div>
                  );
                }

                // Student Session Styling
                const s = studentMap.get(c.studentId || '');
                return (
                  <div 
                    key={c.id}
                    onClick={(e) => handleClassDetailsClick(e, c)}
                    className={`px-1.5 py-1 rounded border shadow-sm transition-transform active:scale-95 ${s?.color || 'bg-gray-100 text-gray-800'}`}
                  >
                    <div className="flex flex-col gap-0.5">
                      <div className="text-[10px] font-bold truncate">
                        {c.startTime ? formatTime(c.startTime) : (currentView === 'MASTER' ? s?.name : 'Scheduled')}
                      </div>
                      {currentView === 'MASTER' && c.startTime && (
                        <div className="text-[10px] truncate opacity-80">{s?.name}</div>
                      )}
                    </div>
                  </div>
                );
              })}
          </div>
        </div>
      );
    }

    return (
      <div className="grid grid-cols-7 border-l border-t border-gray-100 rounded-xl overflow-hidden shadow-sm bg-white">
        {dayLabels.map(label => (
          <div key={label} className="bg-gray-50 py-3 border-r border-b border-gray-100 text-center text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em]">
            {label}
          </div>
        ))}
        {days}
      </div>
    );
  };

  const currentStudent = currentView === 'MASTER' ? null : studentMap.get(currentView);

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#f8fafc]">
      {/* Sidebar - Hidden on print */}
      <aside className="no-print w-full md:w-64 bg-white border-r border-gray-200 flex flex-col flex-shrink-0">
        <div className="p-6">
          <div className="flex items-center gap-3 text-indigo-600 mb-10">
            <div className="w-9 h-9 bg-indigo-600 rounded-lg flex items-center justify-center text-white shadow-lg shadow-indigo-200">
              <CalendarIcon className="w-5 h-5" />
            </div>
            <div>
              <h1 className="text-base font-bold text-gray-900 leading-none">TutorSync</h1>
              <span className="text-[10px] text-gray-400 font-semibold tracking-wider uppercase">Planner</span>
            </div>
          </div>

          <div className="space-y-1.5">
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-3 px-3">Main View</p>
            <button 
              onClick={() => setCurrentView('MASTER')}
              className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${currentView === 'MASTER' ? 'bg-indigo-50 text-indigo-700 font-semibold shadow-sm border border-indigo-100' : 'text-gray-500 hover:bg-gray-50'}`}
            >
              <Users className="w-4 h-4" />
              <span className="text-sm">Master Schedule</span>
            </button>
          </div>

          <div className="mt-10 space-y-1.5 overflow-y-auto max-h-[calc(100vh-320px)]">
            <div className="flex items-center justify-between mb-3 px-3">
              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Student Sheets</p>
              <button 
                onClick={() => setIsStudentModalOpen(true)}
                className="p-1.5 hover:bg-gray-50 rounded-lg text-gray-400 hover:text-indigo-600 transition-colors"
                title="Manage Students"
              >
                <Settings className="w-4 h-4" />
              </button>
            </div>

            {students.map(s => (
              <button 
                key={s.id}
                onClick={() => setCurrentView(s.id)}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all group ${currentView === s.id ? 'bg-indigo-50 text-indigo-700 font-semibold shadow-sm border border-indigo-100' : 'text-gray-500 hover:bg-gray-50'}`}
              >
                <div className={`w-2.5 h-2.5 rounded-full border-2 border-white ${s.color.split(' ')[0]} ${currentView === s.id ? 'scale-110 shadow-sm' : ''}`} />
                <span className="text-sm truncate">{s.name}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="mt-auto p-6 bg-gray-50/50 border-t border-gray-100">
          <div className="text-[10px] font-medium text-gray-400 mb-2 px-1 text-center">Tip: Add events or sessions in Master View</div>
          <button 
            onClick={() => {
              setEditingClass({ 
                studentId: currentView === 'MASTER' ? undefined : currentView,
                type: currentView === 'MASTER' ? 'EVENT' : 'SESSION'
              });
              setIsClassModalOpen(true);
            }}
            className="w-full bg-white border border-gray-200 hover:border-indigo-300 hover:text-indigo-600 text-gray-600 font-bold py-2.5 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm active:scale-95"
          >
            <Plus className="w-4 h-4" />
            <span className="text-sm">Add New Entry</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-h-0 overflow-hidden">
        {/* Header */}
        <header className="no-print bg-white border-b border-gray-200 px-6 py-4 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
             <div className="bg-indigo-50 p-2 rounded-lg">
                <CalendarIcon className="w-5 h-5 text-indigo-600" />
             </div>
             <div>
                <h2 className="text-lg font-bold text-gray-900 flex items-center gap-2">
                  {currentView === 'MASTER' ? 'Master Overview' : `${currentStudent?.name}'s Schedule`}
                </h2>
                <div className="flex items-center gap-1.5 text-gray-400 text-[11px] font-medium uppercase tracking-wider">
                  <span>{currentMonthName} {year}</span>
                  {currentView !== 'MASTER' && (
                    <>
                      <span className="text-gray-200">|</span>
                      <span className="text-indigo-500">Individual Privacy Sheet</span>
                    </>
                  )}
                </div>
             </div>
          </div>

          <div className="flex items-center gap-3">
            <div className="flex bg-gray-50 rounded-xl p-1 border border-gray-100">
              <button 
                onClick={handlePrevMonth}
                className="p-1.5 hover:bg-white hover:shadow-sm rounded-lg transition-all text-gray-500"
              >
                <ChevronLeft className="w-4 h-4" />
              </button>
              <div className="px-3 py-1.5 text-xs font-bold text-gray-700 min-w-[120px] text-center">
                {currentMonthName}
              </div>
              <button 
                onClick={handleNextMonth}
                className="p-1.5 hover:bg-white hover:shadow-sm rounded-lg transition-all text-gray-500"
              >
                <ChevronRight className="w-4 h-4" />
              </button>
            </div>

            <button 
              onClick={handlePrint}
              className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 rounded-xl text-white text-xs font-bold transition-all shadow-lg shadow-indigo-100 active:scale-95"
            >
              <Share2 className="w-3.5 h-3.5" />
              Export View
            </button>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto p-6 md:p-10">
          <div className="max-w-5xl mx-auto">
            {currentView === 'MASTER' ? (
              <div className="mb-6 flex flex-wrap gap-2.5 no-print items-center">
                <div className="flex items-center gap-2 bg-gray-800 px-3 py-1.5 rounded-lg border border-gray-900 text-[11px] font-bold text-white shadow-sm">
                  <Star className="w-2.5 h-2.5 text-amber-400 fill-amber-400" />
                  General Events
                </div>
                <div className="w-px h-4 bg-gray-200 mx-2" />
                {students.map(s => (
                  <div key={s.id} className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border border-gray-100 text-[11px] font-semibold text-gray-600 shadow-sm transition-all hover:border-indigo-100">
                    <div className={`w-2 h-2 rounded-full ${s.color.split(' ')[0]}`} />
                    {s.name}
                  </div>
                ))}
              </div>
            ) : (
               <div className="mb-6 flex items-center gap-3 px-4 py-3 bg-indigo-50 border border-indigo-100 rounded-xl no-print">
                  <Info className="w-4 h-4 text-indigo-500" />
                  <p className="text-xs text-indigo-700 font-medium">
                    <strong className="font-bold">Painter Mode:</strong> Click days to toggle <span className="underline decoration-indigo-300 decoration-2 underline-offset-2">{currentStudent?.name}</span>. Note: General events are only visible on the Master View.
                  </p>
               </div>
            )}

            <div className="print:m-0">
               {renderCalendar()}
            </div>

            <footer className="mt-8 text-center no-print">
               <p className="text-gray-400 text-[10px] font-medium tracking-wide">© TutorSync Schedule Pro — Privacy Protected Sheet</p>
            </footer>
          </div>
        </div>
      </main>

      <ClassModal 
        isOpen={isClassModalOpen}
        onClose={() => {
          setIsClassModalOpen(false);
          setEditingClass(undefined);
        }}
        onSave={addOrUpdateClass}
        onDelete={deleteClass}
        students={students}
        initialData={editingClass}
      />

      <StudentModal 
        isOpen={isStudentModalOpen}
        onClose={() => setIsStudentModalOpen(false)}
        students={students}
        onAdd={addStudent}
        onDelete={deleteStudent}
      />
    </div>
  );
};

export default App;

export interface Student {
  id: string;
  name: string;
  color: string;
}

export interface ClassSession {
  id: string;
  studentId?: string; // Optional for general events
  title?: string;     // For general events like "School Break"
  type: 'SESSION' | 'EVENT';
  date: string;       // Start Date (ISO format: YYYY-MM-DD)
  endDate?: string;   // Optional End Date for events (ISO format: YYYY-MM-DD)
  startTime?: string; // HH:mm (Optional)
  duration?: number;  // in minutes (Optional)
  notes?: string;
}

export type ViewType = 'MASTER' | string; // 'MASTER' or Student.id

import React, { useState, useEffect } from 'react';
import { Student, ClassSession } from '../types';
import { X, GraduationCap, Calendar as CalendarIcon, ArrowRight } from 'lucide-react';

interface ClassModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (session: Partial<ClassSession>) => void;
  onDelete?: (id: string) => void;
  students: Student[];
  initialData?: Partial<ClassSession>;
}

const ClassModal: React.FC<ClassModalProps> = ({
  isOpen,
  onClose,
  onSave,
  onDelete,
  students,
  initialData
}) => {
  const [type, setType] = useState<'SESSION' | 'EVENT'>('SESSION');
  const [studentId, setStudentId] = useState('');
  const [title, setTitle] = useState('');
  const [date, setDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [startTime, setStartTime] = useState('');
  const [duration, setDuration] = useState<number | undefined>(undefined);
  const [notes, setNotes] = useState('');

  useEffect(() => {
    if (initialData) {
      const isNew = !initialData.id;
      setType(initialData.type || (initialData.studentId ? 'SESSION' : 'EVENT'));
      setStudentId(initialData.studentId || '');
      setTitle(initialData.title || '');
      setDate(initialData.date || '');
      setEndDate(initialData.endDate || initialData.date || '');

      // Default time/duration for NEW entries, use initial for edits
      if (isNew) {
        setStartTime(initialData.startTime || '20:00');
        setDuration(initialData.duration || 60);
      } else {
        setStartTime(initialData.startTime || '');
        setDuration(initialData.duration);
      }

      setNotes(initialData.notes || '');
    }
  }, [initialData, isOpen]);

  // Sync endDate to date if it's currently the same or empty (helpful for one-click ranges)
  const handleDateChange = (val: string) => {
    setDate(val);
    if (!endDate || endDate < val) {
      setEndDate(val);
    }
  };

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      id: initialData?.id,
      type,
      studentId: type === 'SESSION' ? studentId : undefined,
      title: type === 'EVENT' ? title : undefined,
      date,
      endDate: type === 'EVENT' ? endDate : undefined,
      startTime: startTime || undefined,
      duration: duration || undefined,
      notes
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
          <h2 className="text-xl font-bold text-gray-800">
            {initialData?.id ? 'Edit Entry' : 'Add to Schedule'}
          </h2>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-xl transition-colors">
            <X className="w-5 h-5 text-gray-500" />
          </button>
        </div>

        {/* Type Toggle */}
        <div className="flex p-1 bg-gray-100 mx-6 mt-6 rounded-xl">
          <button
            type="button"
            onClick={() => setType('SESSION')}
            className={`flex-1 flex items-center justify-center gap-2 py-2 text-xs font-bold rounded-lg transition-all ${type === 'SESSION' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            < GraduationCap className="w-4 h-4" />
            Student Class
          </button>
          <button
            type="button"
            onClick={() => setType('EVENT')}
            className={`flex-1 flex items-center justify-center gap-2 py-2 text-xs font-bold rounded-lg transition-all ${type === 'EVENT' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
          >
            <CalendarIcon className="w-4 h-4" />
            General Event
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          {type === 'SESSION' ? (
            <div>
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 ml-1">Student</label>
              <select
                required
                className="w-full border border-gray-200 rounded-xl p-3 text-gray-900 bg-gray-50/50 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
                value={studentId}
                onChange={(e) => setStudentId(e.target.value)}
              >
                <option value="">Select a student...</option>
                {students.map(s => (
                  <option key={s.id} value={s.id}>{s.name}</option>
                ))}
              </select>
            </div>
          ) : (
            <div>
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 ml-1">Event Title</label>
              <input
                type="text"
                required
                placeholder="e.g. Math Workshop, School Holiday"
                className="w-full border border-gray-200 rounded-xl p-3 text-gray-900 bg-gray-50/50 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
              />
            </div>
          )}

          {type === 'EVENT' ? (
            <div className="grid grid-cols-[1fr,auto,1fr] items-end gap-2">
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 ml-1">From</label>
                <input
                  type="date"
                  required
                  className="w-full border border-gray-200 rounded-xl p-3 text-gray-900 bg-gray-50/50 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all text-xs"
                  value={date}
                  onChange={(e) => handleDateChange(e.target.value)}
                />
              </div>
              <div className="pb-4 text-gray-300">
                <ArrowRight className="w-4 h-4" />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 ml-1">To</label>
                <input
                  type="date"
                  required
                  min={date}
                  className="w-full border border-gray-200 rounded-xl p-3 text-gray-900 bg-gray-50/50 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all text-xs"
                  value={endDate}
                  onChange={(e) => setEndDate(e.target.value)}
                />
              </div>
            </div>
          ) : (
            <div>
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 ml-1">Date</label>
              <input
                type="date"
                required
                className="w-full border border-gray-200 rounded-xl p-3 text-gray-900 bg-gray-50/50 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
                value={date}
                onChange={(e) => setDate(e.target.value)}
              />
            </div>
          )}

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 ml-1 text-gray-400">Time (Opt)</label>
              <input
                type="time"
                className="w-full border border-gray-200 rounded-xl p-3 text-gray-900 bg-gray-50/50 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
                value={startTime}
                onChange={(e) => setStartTime(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 ml-1 text-gray-400">Duration</label>
              <input
                type="number"
                min="0"
                step="30"
                placeholder="60"
                className="w-full border border-gray-200 rounded-xl p-3 text-gray-900 bg-gray-50/50 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
                value={duration || ''}
                onChange={(e) => setDuration(e.target.value ? parseInt(e.target.value) : undefined)}
              />
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2 ml-1 text-gray-400">Notes</label>
            <textarea
              className="w-full border border-gray-200 rounded-xl p-3 text-gray-900 bg-gray-50/50 focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
              rows={2}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="Any additional details..."
            />
          </div>

          <div className="pt-4 flex flex-col gap-2">
            <button
              type="submit"
              className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-xl transition-all shadow-lg shadow-indigo-100 active:scale-[0.98]"
            >
              Save to Schedule
            </button>
            {initialData?.id && onDelete && (
              <button
                type="button"
                onClick={() => {
                  onDelete(initialData.id!);
                  onClose();
                }}
                className="w-full text-rose-600 hover:bg-rose-50 font-bold py-2 rounded-xl transition-all"
              >
                Delete Entry
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
};

export default ClassModal;

import React, { useState, useEffect, useMemo } from 'react';
import { Student, ClassSession, ViewType } from './types';
import { INITIAL_STUDENTS } from './constants';
import { MONTH_NAMES, getDaysInMonth, getFirstDayOfMonth, formatTime } from './utils/dateUtils';
import ClassModal from './components/ClassModal';
import StudentModal from './components/StudentModal';
import { 
  Users, 
  Calendar as CalendarIcon, 
  Plus, 
  ChevronLeft, 
  ChevronRight, 
  Share2, 
  Settings,
  Info,
  Star
} from 'lucide-react';

const App: React.FC = () => {
  // State for data
  const [students, setStudents] = useState<Student[]>(() => {
    const saved = localStorage.getItem('tutor_students');
    return saved ? JSON.parse(saved) : INITIAL_STUDENTS;
  });

  const [classes, setClasses] = useState<ClassSession[]>(() => {
    const saved = localStorage.getItem('tutor_classes');
    return saved ? JSON.parse(saved) : [];
  });

  // UI State
  const [currentView, setCurrentView] = useState<ViewType>('MASTER');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [isClassModalOpen, setIsClassModalOpen] = useState(false);
  const [isStudentModalOpen, setIsStudentModalOpen] = useState(false);
  const [editingClass, setEditingClass] = useState<Partial<ClassSession> | undefined>(undefined);

  // Sync to localStorage
  useEffect(() => {
    localStorage.setItem('tutor_students', JSON.stringify(students));
  }, [students]);

  useEffect(() => {
    localStorage.setItem('tutor_classes', JSON.stringify(classes));
  }, [classes]);

  // Derived Values
  const year = selectedDate.getFullYear();
  const month = selectedDate.getMonth();
  const daysInMonth = getDaysInMonth(year, month);
  const startDay = getFirstDayOfMonth(year, month);
  const currentMonthName = MONTH_NAMES[month];

  const filteredClasses = useMemo(() => {
    // We return all potentially relevant classes for the current year/month.
    // The date comparison happens in the loop during rendering for multi-day support.
    return classes.filter(c => {
      const [cYear, cMonth] = c.date.split('-').map(Number);
      const [eYear, eMonth] = (c.endDate || c.date).split('-').map(Number);

      // Basic month/year range overlap check
      const startInMonth = cYear === year && (cMonth - 1) === month;
      const endInMonth = eYear === year && (eMonth - 1) === month;
      const spansMonth = (cYear < year || (cYear === year && (cMonth - 1) <= month)) && 
                         (eYear > year || (eYear === year && (eMonth - 1) >= month));

      const isRelevantMonth = startInMonth || endInMonth || spansMonth;

      if (currentView === 'MASTER') return isRelevantMonth;
      // In individual views, only show SESSIONS for that specific student
      return isRelevantMonth && c.type === 'SESSION' && c.studentId === currentView;
    });
  }, [classes, year, month, currentView]);

  const studentMap = useMemo(() => {
    const map = new Map<string, Student>();
    students.forEach(s => map.set(s.id, s));
    return map;
  }, [students]);

  // Handlers
  const handlePrevMonth = () => setSelectedDate(new Date(year, month - 1, 1));
  const handleNextMonth = () => setSelectedDate(new Date(year, month + 1, 1));

  const addOrUpdateClass = (data: Partial<ClassSession>) => {
    if (data.id) {
      setClasses(prev => prev.map(c => c.id === data.id ? { ...c, ...data } as ClassSession : c));
    } else {
      const newClass: ClassSession = {
        ...data as Omit<ClassSession, 'id'>,
        id: Math.random().toString(36).substr(2, 9)
      };
      setClasses(prev => [...prev, newClass]);
    }
    setEditingClass(undefined);
  };

  const deleteClass = (id: string) => {
    setClasses(prev => prev.filter(c => c.id !== id));
  };

  const addStudent = (name: string, color: string) => {
    const newStudent: Student = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      color
    };
    setStudents(prev => [...prev, newStudent]);
  };

  const deleteStudent = (id: string) => {
    setStudents(prev => prev.filter(s => s.id !== id));
    setClasses(prev => prev.filter(c => c.studentId !== id));
    if (currentView === id) setCurrentView('MASTER');
  };

  const handleDayClick = (day: number) => {
    const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

    if (currentView !== 'MASTER') {
      const existingClassIdx = classes.findIndex(c => c.date === dateStr && c.studentId === currentView && c.type === 'SESSION');
      if (existingClassIdx > -1) {
        setClasses(prev => prev.filter((_, i) => i !== existingClassIdx));
      } else {
        const newClass: ClassSession = {
          id: Math.random().toString(36).substr(2, 9),
          studentId: currentView,
          type: 'SESSION',
          date: dateStr
        };
        setClasses(prev => [...prev, newClass]);
      }
    } else {
      setEditingClass({ date: dateStr, type: 'SESSION' });
      setIsClassModalOpen(true);
    }
  };

  const handleClassDetailsClick = (e: React.MouseEvent, c: ClassSession) => {
    e.stopPropagation();
    setEditingClass(c);
    setIsClassModalOpen(true);
  };

  const handlePrint = () => {
    window.print();
  };

  // Render helpers
  const renderCalendar = () => {
    const days = [];
    const dayLabels = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

    for (let i = 0; i < startDay; i++) {
      days.push(<div key={`empty-${i}`} className="bg-gray-50 h-32 border border-gray-100"></div>);
    }

    for (let d = 1; d <= daysInMonth; d++) {
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;

      // For multi-day events, check if current date is between start and end inclusive
      const dayClasses = filteredClasses.filter(c => {
        if (c.type === 'EVENT' && c.endDate) {
          return dateStr >= c.date && dateStr <= c.endDate;
        }
        return c.date === dateStr;
      });

      days.push(
        <div 
          key={d} 
          onClick={() => handleDayClick(d)}
          className={`h-32 border border-gray-100 p-2 overflow-y-auto transition-colors cursor-pointer group relative ${currentView !== 'MASTER' ? 'hover:bg-indigo-50/50 bg-white' : 'bg-white hover:bg-gray-50'}`}
        >
          <div className="flex justify-between items-start mb-1">
            <span className="text-sm font-semibold text-gray-400 group-hover:text-indigo-600 transition-colors">{d}</span>
            {currentView !== 'MASTER' && (
              <Plus className="w-3.5 h-3.5 text-indigo-300 opacity-0 group-hover:opacity-100 transition-opacity" />
            )}
          </div>
          <div className="space-y-1">
            {dayClasses
              .sort((a, b) => (a.startTime || '00:00').localeCompare(b.startTime || '00:00'))
              .map(c => {
                if (c.type === 'EVENT') {
                  const isStart = dateStr === c.date;
                  const isEnd = dateStr === c.endDate;
                  return (
                    <div 
                      key={c.id + dateStr}
                      onClick={(e) => handleClassDetailsClick(e, c)}
                      className={`px-1.5 py-1 transition-transform active:scale-95 bg-gray-800 text-white border-gray-900 shadow-sm ${isStart && isEnd ? 'rounded border' : isStart ? 'rounded-l border-l border-t border-b' : isEnd ? 'rounded-r border-r border-t border-b' : 'border-t border-b'}`}
                    >
                      <div className="flex items-center gap-1">
                        <Star className="w-2 h-2 text-amber-400 fill-amber-400 flex-shrink-0" />
                        <div className="text-[10px] font-bold truncate">
                          {c.startTime && isStart ? `${formatTime(c.startTime)} ` : ''}{c.title}
                        </div>
                      </div>
                    </div>
                  );
                }

                const s = studentMap.get(c.studentId || '');
                return (
                  <div 
                    key={c.id}
                    onClick={(e) => handleClassDetailsClick(e, c)}
                    className={`px-1.5 py-1 rounded border shadow-sm transition-transform active:scale-95 ${s?.color || 'bg-gray-100 text-gray-800'}`}
                  >
                    <div className="flex flex-col gap-0.5">
                      <div className="text-[10px] font-bold truncate">
                        {c.startTime ? formatTime(c.startTime) : (currentView === 'MASTER' ? s?.name : 'Scheduled')}
                      </div>
                      {currentView === 'MASTER' && c.startTime && (
                        <div className="text-[10px] truncate opacity-80">{s?.name}</div>
                      )}
                    </div>
                  </div>
                );
              })}
          </div>
        </div>
      );
    }

    return (
      <div className="grid grid-cols-7 border-l border-t border-gray-100 rounded-xl overflow-hidden shadow-sm bg-white">
        {dayLabels.map(label => (
          <div key={label} className="bg-gray-50 py-3 border-r border-b border-gray-100 text-center text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em]">
            {label}
          </div>
        ))}
        {days}
      </div>
    );
  };

  const currentStudent = currentView === 'MASTER' ? null : studentMap.get(currentView);

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#f8fafc]">
      <aside className="no-print w-full md:w-64 bg-white border-r border-gray-200 flex flex-col flex-shrink-0">
        <div className="p-6">
          <div className="flex items-center gap-3 text-indigo-600 mb-10">
            <div className="w-9 h-9 bg-indigo-600 rounded-lg flex items-center justify-center text-white shadow-lg shadow-indigo-200">
              <CalendarIcon className="w-5 h-5" />
            </div>
            <div>
              <h1 className="text-base font-bold text-gray-900 leading-none">TutorSync</h1>
              <span className="text-[10px] text-gray-400 font-semibold tracking-wider uppercase">Planner</span>
            </div>
          </div>

          <div className="space-y-1.5">
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-3 px-3">Main View</p>
            <button 
              onClick={() => setCurrentView('MASTER')}
              className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${currentView === 'MASTER' ? 'bg-indigo-50 text-indigo-700 font-semibold shadow-sm border border-indigo-100' : 'text-gray-500 hover:bg-gray-50'}`}
            >
              <Users className="w-4 h-4" />
              <span className="text-sm">Master Schedule</span>
            </button>
          </div>

          <div className="mt-10 space-y-1.5 overflow-y-auto max-h-[calc(100vh-320px)]">
            <div className="flex items-center justify-between mb-3 px-3">
              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Student Sheets</p>
              <button 
                onClick={() => setIsStudentModalOpen(true)}
                className="p-1.5 hover:bg-gray-50 rounded-lg text-gray-400 hover:text-indigo-600 transition-colors"
                title="Manage Students"
              >
                <Settings className="w-4 h-4" />
              </button>
            </div>

            {students.map(s => (
              <button 
                key={s.id}
                onClick={() => setCurrentView(s.id)}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all group ${currentView === s.id ? 'bg-indigo-50 text-indigo-700 font-semibold shadow-sm border border-indigo-100' : 'text-gray-500 hover:bg-gray-50'}`}
              >
                <div className={`w-2.5 h-2.5 rounded-full border-2 border-white ${s.color.split(' ')[0]} ${currentView === s.id ? 'scale-110 shadow-sm' : ''}`} />
                <span className="text-sm truncate">{s.name}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="mt-auto p-6 bg-gray-50/50 border-t border-gray-100">
          <div className="text-[10px] font-medium text-gray-400 mb-2 px-1 text-center">Tip: Add events or sessions in Master View</div>
          <button 
            onClick={() => {
              setEditingClass({ 
                studentId: currentView === 'MASTER' ? undefined : currentView,
                type: currentView === 'MASTER' ? 'EVENT' : 'SESSION'
              });
              setIsClassModalOpen(true);
            }}
            className="w-full bg-white border border-gray-200 hover:border-indigo-300 hover:text-indigo-600 text-gray-600 font-bold py-2.5 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm active:scale-95"
          >
            <Plus className="w-4 h-4" />
            <span className="text-sm">Add New Entry</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-h-0 overflow-hidden">
        <header className="no-print bg-white border-b border-gray-200 px-6 py-4 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
             <div className="bg-indigo-50 p-2 rounded-lg">
                <CalendarIcon className="w-5 h-5 text-indigo-600" />
             </div>
             <div>
                <h2 className="text-lg font-bold text-gray-900 flex items-center gap-2">
                  {currentView === 'MASTER' ? 'Master Overview' : `${currentStudent?.name}'s Schedule`}
                </h2>
                <div className="flex items-center gap-1.5 text-gray-400 text-[11px] font-medium uppercase tracking-wider">
                  <span>{currentMonthName} {year}</span>
                  {currentView !== 'MASTER' && (
