                  <div key={s.id} className="flex items-center gap-2 bg-white px-3 py-1.5 rounded-lg border border-gray-100 text-[11px] font-semibold text-gray-600 shadow-sm transition-all hover:border-indigo-100">
                    <div className={`w-2 h-2 rounded-full ${s.color.split(' ')[0]}`} />
