            <footer className="mt-8 text-center no-print">
               <p className="text-gray-400 text-[10px] font-medium tracking-wide">© TutorSync Schedule Pro — Privacy Protected Sheet</p>
            </footer>
          </div>
        </div>
      </main>

      <ClassModal 
        isOpen={isClassModalOpen}
        onClose={() => {
          setIsClassModalOpen(false);
          setEditingClass(undefined);
        }}
        onSave={addOrUpdateClass}
        onDelete={deleteClass}
        students={students}
        initialData={editingClass}
      />

      <StudentModal 
        isOpen={isStudentModalOpen}
        onClose={() => setIsStudentModalOpen(false)}
        students={students}
        onAdd={addStudent}
        onDelete={deleteStudent}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Student, ClassSession, ViewType } from './types';
import { INITIAL_STUDENTS } from './constants';
import { MONTH_NAMES, getDaysInMonth, getFirstDayOfMonth, formatTime } from './utils/dateUtils';
import ClassModal from './components/ClassModal';
import StudentModal from './components/StudentModal';
import { 
  Users, 
  Calendar as CalendarIcon, 
  Plus, 
  ChevronLeft, 
  ChevronRight, 
  Share2, 
  Settings,
  Info,
  Star,
  StickyNote
} from 'lucide-react';

const App: React.FC = () => {
  // State for data
  const [students, setStudents] = useState<Student[]>(() => {
    const saved = localStorage.getItem('tutor_students');
    return saved ? JSON.parse(saved) : INITIAL_STUDENTS;
  });

  const [classes, setClasses] = useState<ClassSession[]>(() => {
    const saved = localStorage.getItem('tutor_classes');
    return saved ? JSON.parse(saved) : [];
  });

  // UI State
  const [currentView, setCurrentView] = useState<ViewType>('MASTER');
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [isClassModalOpen, setIsClassModalOpen] = useState(false);
  const [isStudentModalOpen, setIsStudentModalOpen] = useState(false);
  const [editingClass, setEditingClass] = useState<Partial<ClassSession> | undefined>(undefined);

  // Sync to localStorage
  useEffect(() => {
    localStorage.setItem('tutor_students', JSON.stringify(students));
  }, [students]);

  useEffect(() => {
    localStorage.setItem('tutor_classes', JSON.stringify(classes));
  }, [classes]);

  // Derived Values
  const year = selectedDate.getFullYear();
  const month = selectedDate.getMonth();
  const daysInMonth = getDaysInMonth(year, month);
  const startDay = getFirstDayOfMonth(year, month);
  const currentMonthName = MONTH_NAMES[month];

  const filteredClasses = useMemo(() => {
    return classes.filter(c => {
      const [cYear, cMonth] = c.date.split('-').map(Number);
      const [eYear, eMonth] = (c.endDate || c.date).split('-').map(Number);

      const startInMonth = cYear === year && (cMonth - 1) === month;
      const endInMonth = eYear === year && (eMonth - 1) === month;
      const spansMonth = (cYear < year || (cYear === year && (cMonth - 1) <= month)) && 
                         (eYear > year || (eYear === year && (eMonth - 1) >= month));

      const isRelevantMonth = startInMonth || endInMonth || spansMonth;

      if (currentView === 'MASTER') return isRelevantMonth;
      return isRelevantMonth && c.type === 'SESSION' && c.studentId === currentView;
    });
  }, [classes, year, month, currentView]);

  const studentMap = useMemo(() => {
    const map = new Map<string, Student>();
    students.forEach(s => map.set(s.id, s));
    return map;
  }, [students]);

  // Handlers
  const handlePrevMonth = () => setSelectedDate(new Date(year, month - 1, 1));
  const handleNextMonth = () => setSelectedDate(new Date(year, month + 1, 1));

  const addOrUpdateClass = (data: Partial<ClassSession>) => {
    if (data.id) {
      setClasses(prev => prev.map(c => c.id === data.id ? { ...c, ...data } as ClassSession : c));
    } else {
      const newClass: ClassSession = {
        ...data as Omit<ClassSession, 'id'>,
        id: Math.random().toString(36).substr(2, 9)
      };
      setClasses(prev => [...prev, newClass]);
    }
    setEditingClass(undefined);
  };

  const deleteClass = (id: string) => {
    setClasses(prev => prev.filter(c => c.id !== id));
  };

  const addStudent = (name: string, color: string) => {
    const newStudent: Student = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      color
    };
    setStudents(prev => [...prev, newStudent]);
  };

  const deleteStudent = (id: string) => {
    setStudents(prev => prev.filter(s => s.id !== id));
    setClasses(prev => prev.filter(c => c.studentId !== id));
    if (currentView === id) setCurrentView('MASTER');
  };

  const handleDayClick = (day: number) => {
    const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

    if (currentView !== 'MASTER') {
      const existingClassIdx = classes.findIndex(c => c.date === dateStr && c.studentId === currentView && c.type === 'SESSION');
      if (existingClassIdx > -1) {
        setClasses(prev => prev.filter((_, i) => i !== existingClassIdx));
      } else {
        const newClass: ClassSession = {
          id: Math.random().toString(36).substr(2, 9),
          studentId: currentView,
          type: 'SESSION',
          date: dateStr
        };
        setClasses(prev => [...prev, newClass]);
      }
    } else {
      setEditingClass({ date: dateStr, type: 'SESSION' });
      setIsClassModalOpen(true);
    }
  };

  const handleClassDetailsClick = (e: React.MouseEvent, c: ClassSession) => {
    e.stopPropagation();
    setEditingClass(c);
    setIsClassModalOpen(true);
  };

  const handlePrint = () => {
    window.print();
  };

  const renderCalendar = () => {
    const days = [];
    const dayLabels = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

    for (let i = 0; i < startDay; i++) {
      days.push(<div key={`empty-${i}`} className="bg-gray-50 h-32 border border-gray-100"></div>);
    }

    for (let d = 1; d <= daysInMonth; d++) {
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;

      const dayClasses = filteredClasses.filter(c => {
        if (c.type === 'EVENT' && c.endDate) {
          return dateStr >= c.date && dateStr <= c.endDate;
        }
        return c.date === dateStr;
      });

      days.push(
        <div 
          key={d} 
          onClick={() => handleDayClick(d)}
          className={`h-32 border border-gray-100 p-2 overflow-y-auto transition-colors cursor-pointer group relative ${currentView !== 'MASTER' ? 'hover:bg-indigo-50/50 bg-white' : 'bg-white hover:bg-gray-50'}`}
        >
          <div className="flex justify-between items-start mb-1">
            <span className="text-sm font-semibold text-gray-400 group-hover:text-indigo-600 transition-colors">{d}</span>
            {currentView !== 'MASTER' && (
              <Plus className="w-3.5 h-3.5 text-indigo-300 opacity-0 group-hover:opacity-100 transition-opacity" />
            )}
          </div>
          <div className="space-y-1">
            {dayClasses
              .sort((a, b) => (a.startTime || '00:00').localeCompare(b.startTime || '00:00'))
              .map(c => {
                if (c.type === 'EVENT') {
                  const isStart = dateStr === c.date;
                  const isEnd = dateStr === c.endDate;
                  return (
                    <div 
                      key={c.id + dateStr}
                      onClick={(e) => handleClassDetailsClick(e, c)}
                      className={`px-1.5 py-1 transition-transform active:scale-95 border-gray-900 shadow-sm ${c.color || 'bg-gray-800 text-white'} ${isStart && isEnd ? 'rounded border' : isStart ? 'rounded-l border-l border-t border-b' : isEnd ? 'rounded-r border-r border-t border-b' : 'border-t border-b'}`}
                    >
                      <div className="flex items-center justify-between gap-1">
                        <div className="flex items-center gap-1 min-w-0">
                          <Star className="w-2 h-2 text-amber-400 fill-amber-400 flex-shrink-0" />
                          <div className="text-[10px] font-bold truncate">
                            {c.startTime && isStart ? `${formatTime(c.startTime)} ` : ''}{c.title}
                          </div>
                        </div>
                        {c.notes && <StickyNote className="w-2.5 h-2.5 flex-shrink-0" />}
                      </div>
                    </div>
                  );
                }

                const s = studentMap.get(c.studentId || '');
                const studentName = s?.name || 'Unknown Student';

                return (
                  <div 
                    key={c.id}
                    onClick={(e) => handleClassDetailsClick(e, c)}
                    className={`px-1.5 py-1 rounded border shadow-sm transition-transform active:scale-95 ${s?.color || 'bg-gray-100 text-gray-800'}`}
                  >
                    <div className="flex flex-col gap-0.5">
                      <div className="flex items-center justify-between gap-1">
                        <div className="text-[10px] font-bold truncate">
                          {c.startTime ? formatTime(c.startTime) : studentName}
                        </div>
                        {c.notes && <StickyNote className="w-2.5 h-2.5 flex-shrink-0" />}
                      </div>
                      {/* Sub-label: Show name if time is already shown in primary label */}
                      {c.startTime && (
                        <div className="text-[10px] font-medium truncate">{studentName}</div>
                      )}
                    </div>
                  </div>
                );
              })}
          </div>
        </div>
      );
    }

    return (
      <div className="grid grid-cols-7 border-l border-t border-gray-100 rounded-xl overflow-hidden shadow-sm bg-white">
        {dayLabels.map(label => (
          <div key={label} className="bg-gray-50 py-3 border-r border-b border-gray-100 text-center text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em]">
            {label}
          </div>
        ))}
        {days}
      </div>
    );
  };

  const currentStudent = currentView === 'MASTER' ? null : studentMap.get(currentView);

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#f8fafc]">
      <aside className="no-print w-full md:w-64 bg-white border-r border-gray-200 flex flex-col flex-shrink-0">
        <div className="p-6">
          <div className="flex items-center gap-3 text-indigo-600 mb-10">
            <div className="w-9 h-9 bg-indigo-600 rounded-lg flex items-center justify-center text-white shadow-lg shadow-indigo-200">
              <CalendarIcon className="w-5 h-5" />
            </div>
            <div>
              <h1 className="text-base font-bold text-gray-900 leading-none">TutorSync</h1>
              <span className="text-[10px] text-gray-400 font-semibold tracking-wider uppercase">Planner</span>
            </div>
          </div>

          <div className="space-y-1.5">
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-3 px-3">Main View</p>
            <button 
              onClick={() => setCurrentView('MASTER')}
              className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${currentView === 'MASTER' ? 'bg-indigo-50 text-indigo-700 font-semibold shadow-sm border border-indigo-100' : 'text-gray-500 hover:bg-gray-50'}`}
            >
              <Users className="w-4 h-4" />
              <span className="text-sm">Master Schedule</span>
            </button>
          </div>

          <div className="mt-10 space-y-1.5 overflow-y-auto max-h-[calc(100vh-320px)]">
            <div className="flex items-center justify-between mb-3 px-3">
              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Student Sheets</p>
              <button 
                onClick={() => setIsStudentModalOpen(true)}
                className="p-1.5 hover:bg-gray-50 rounded-lg text-gray-400 hover:text-indigo-600 transition-colors"
                title="Manage Students"
              >
                <Settings className="w-4 h-4" />
              </button>
            </div>

            {students.map(s => (
              <button 
                key={s.id}
                onClick={() => setCurrentView(s.id)}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all group ${currentView === s.id ? 'bg-indigo-50 text-indigo-700 font-semibold shadow-sm border border-indigo-100' : 'text-gray-500 hover:bg-gray-50'}`}
              >
                <div className={`w-2.5 h-2.5 rounded-full border-2 border-white ${s.color.split(' ')[0]} ${currentView === s.id ? 'scale-110 shadow-sm' : ''}`} />
                <span className="text-sm truncate">{s.name}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="mt-auto p-6 bg-gray-50/50 border-t border-gray-100">
          <div className="text-[10px] font-medium text-gray-400 mb-2 px-1 text-center">Tip: Add events or sessions in Master View</div>
          <button 
            onClick={() => {
              setEditingClass({ 
                studentId: currentView === 'MASTER' ? undefined : currentView,
                type: currentView === 'MASTER' ? 'EVENT' : 'SESSION'
              });
              setIsClassModalOpen(true);
            }}
            className="w-full bg-white border border-gray-200 hover:border-indigo-300 hover:text-indigo-600 text-gray-600 font-bold py-2.5 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm active:scale-95"
          >
            <Plus className="w-4 h-4" />
            <span className="text-sm">Add New Entry</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-h-0 overflow-hidden">
        <header className="no-print bg-white border-b border-gray-200 px-6 py-4 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
             <div className="bg-indigo-50 p-2 rounded-lg">
                <CalendarIcon className="w-5 h-5 text-indigo-600" />
             </div>
             <div>
                <h2 className="text-lg font-bold text-gray-900 flex items-center gap-2">
                  {currentView === 'MASTER' ? 'Master Overview' : `${currentStudent?.name}'s Schedule`}
                </h2>
                <div className="flex items-center gap-1.5 text-gray-400 text-[11px] font-medium uppercase tracking-wider">
                  <span>{currentMonthName} {year}</span>
                  {currentView !== 'MASTER' && (
                    <>
                      <span className="text-gray-200">|</span>
                      <span className="text-indigo-500">Individual Privacy Sheet</span>
                    </>
                  )}
                </div>
             </div>
          </div>

          <div className="flex items-center gap-3">
            <div className="flex bg-gray-50 rounded-xl p-1 border border-gray-100">
              <button 
                onClick={handlePrevMonth}
                className="p-1.5 hover:bg-white hover:shadow-sm rounded-lg transition-all text-gray-500"
              >
                <ChevronLeft className="w-4 h-4" />
              </button>
              <div className="px-3 py-1.5 text-xs font-bold text-gray-700 min-w-[120px] text-center">
                {currentMonthName}
              </div>
              <button 
                onClick={handleNextMonth}
                className="p-1.5 hover:bg-white hover:shadow-sm rounded-lg transition-all text-gray-500"
              >
                <ChevronRight className="w-4 h-4" />
              </button>
