              </button>
              <div className="px-3 py-1.5 text-xs font-bold text-gray-700 min-w-[120px] text-center">
                {currentMonthName}
              </div>
              <button 
                onClick={handleNextMonth}
                className="p-1.5 hover:bg-white hover:shadow-sm rounded-lg transition-all text-gray-500"
              >
                <ChevronRight className="w-4 h-4" />
              </button>
            </div>

            <button 
              onClick={handlePrint}
              className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 rounded-xl text-white text-xs font-bold transition-all shadow-lg shadow-indigo-100 active:scale-95"
            >
              <Share2 className="w-3.5 h-3.5" />
              Export View
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-6 md:p-10">
          <div className="max-w-5xl mx-auto">
            {currentView === 'MASTER' ? (
              <div className="mb-6 flex flex-wrap gap-2.5 no-print items-center">
                <div className="flex items-center gap-2 bg-gray-800 px-3 py-1.5 rounded-lg border border-gray-900 text-[11px] font-bold text-white shadow-sm">
                  <Star className="w-2.5 h-2.5 text-amber-400 fill-amber-400" />
